output.message:
{
  "steps": [
    {
      "step_id": "cb_step_1",
      "title": "Select Pelvic CT Volume",
      "simple": "Choose the pelvic CT volume from the Input CT Volume dropdown.",
      "detailed": "This step identifies the CT scan of the pelvis that will be used for segmentation and planning. The correct volume must be selected to ensure the algorithm processes the right anatomical data. Simply pick the volume from the dropdown list."
    },
    {
      "step_id": "cb_step_2",
      "title": "Segment the Pelvis",
      "simple": "Click the \"Run Step 1\" button to start automatic pelvic bone segmentation.",
      "detailed": "This step generates a 3D segmentation of the pelvic bones from the selected CT volume. The segmentation is essential for identifying fracture fragments and planning screw placement. After clicking, wait for the process to complete."
    },
    {
      "step_id": "cb_step_3",
      "title": "Segment Fractures",
      "simple": "Click the \"Run Step 2\" button to detect and segment fracture fragments.",
      "detailed": "This step identifies individual fracture fragments within the pelvic segmentation. Each fragment will be analyzed separately for reduction planning. The output is a labeled set of fragments."
    },
    {
      "step_id": "cb_step_4",
      "title": "Exclude Fragments from Planning",
      "simple": "Untick any fragments you wish to exclude from surgical planning.",
      "detailed": "This step allows you to exclude certain fragments that are not relevant for the reduction plan (e.g., small avulsion fractures or fragments that will not be surgically addressed). Uncheck the boxes next to those fragments. The remaining fragments will be used in subsequent steps."
    },
    {
      "step_id": "cb_step_5",
      "title": "Generate Reduction Template",
      "simple": "Click the \"Run Step 3\" button to generate an initial template for reducing the pelvis.",
      "detailed": "This step creates a target template based on the intact pelvic anatomy or statistical shape model. The template serves as the target alignment for fracture reduction. It positions the undamaged pelvic structures as a reference."
    },
    {
      "step_id": "cb_step_6",
      "title": "Register and Reduce Fragments",
      "simple": "Click the \"Run Step 4\" button to automatically align fracture fragments to the template.",
      "detailed": "This step performs registration to reduce the fracture fragments back to their anatomical positions relative to the template. The result is a virtual reduction showing the reconstructed pelvis."
    },
    {
      "step_id": "cb_step_7",
      "title": "Manual Adjustment Option",
      "simple": "Tick the checkbox if you need to manually adjust any fragment; otherwise proceed to step 11.",
      "detailed": "This decision point lets you choose whether to fine-tune the position of individual fragments manually. If the automatic reduction is satisfactory, skip ahead to screw planning. If not, enable manual adjustment mode."
    },
    {
      "step_id": "cb_step_8",
      "title": "Select Fragment to Adjust",
      "simple": "Choose the fragment you want to adjust from the Fragment dropdown list.",
      "detailed": "Select the specific fracture fragment that requires manual repositioning. This step is only needed if you chose to manually adjust fragments. Pick the fragment from the list."
    },
    {
      "step_id": "cb_step_9",
      "title": "Adjust Fragment Position",
      "simple": "Use the 3D view to drag and rotate the selected fragment into the correct position.",
      "detailed": "Fine-tune the alignment of the selected fragment by moving and rotating it in 3D space. The goal is to achieve anatomically correct reduction. Use the transformation tools provided in the 3D view."
    },
    {
      "step_id": "cb_step_10",
      "title": "Apply Manual Adjustments",
      "simple": "Click the \"Apply adjustments\" button to confirm the manual changes.",
      "detailed": "This step finalizes the manual repositioning of the fragment. The adjustments are incorporated into the reduction model. After clicking, the fragment's new position is locked."
    },
    {
      "step_id": "cb_step_11",
      "title": "Plan Screw Trajectories",
      "simple": "Click the \"Run Step 5\" button to automatically generate screw trajectories based on the reduction.",
      "detailed": "This step calculates optimal screw paths for fixation of the reduced pelvis. It considers bone quality, fragment alignment, and safe corridors. The output is a set of screw trajectories displayed in the 3D view."
    },
    {
      "step_id": "cb_step_12",
      "title": "Edit Screw Trajectories Option",
      "simple": "Tick the checkbox to manually edit screw trajectories, or stop if the plan is satisfactory.",
      "detailed": "Decision point: if the automatically planned screw trajectories are acceptable, you are done. Otherwise, enable editing mode to adjust them manually."
    },
    {
      "step_id": "cb_step_13",
      "title": "Adjust Screw Trajectories",
      "simple": "Use the 3D view to adjust the position and direction of each screw trajectory.",
      "detailed": "Manually refine the screw paths to improve fixation or avoid critical structures. Use the 3D transformation tools to move and rotate the trajectory markers. Ensure screws are positioned safely within bone."
    },
    {
      "step_id": "cb_step_14",
      "title": "Regenerate Screws from Edits",
      "simple": "Click the \"Regenerate screws from edited lines\" button to update the screw models based on your adjusted trajectories.",
      "detailed": "This step recalculates the screw geometry (length, diameter, tip) to match the edited trajectory lines. The updated screw models reflect your manual adjustments."
    },
    {
      "step_id": "cb_step_15",
      "title": "Disable Screw Editing Mode",
      "simple": "Untick the \"Edit Screw trajectories\" checkbox to exit editing mode.",
      "detailed": "This final step deactivates the screw editing interface, completing the planning workflow. The current screw plan is now finalized."
    }
  ]
}
